function wrapLogging(f) {
  return function (...args) {
    try {
      return f(...args);
    } catch (e) {
      console.log('logged error:', e.message);
      throw e;
    }
  };
}

const risky = wrapLogging(function (x) {
  if (x < 0) throw new Error('bad');
  return x + 1;
});

try {
  console.log(risky(2));
  console.log(risky(-5));
} catch (e) {
  console.log('caught outside:', e.message);
}

