function wrapArrayCopyOnWrite(f) {
  return function (array, ...args) {
    var copy = array.slice();
    f(copy, ...args);
    return copy;
  };
}

const push = wrapArrayCopyOnWrite(function (arr, val) {
  arr.push(val);
});

const original = [1, 2, 3];
const result = push(original, 4);
console.log(original);
console.log(result);

